-- Luke Chapter 7
-- Theme: Compassion, Faith, and the Identity of the Son of God
-- 50 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 7,
  'Luke 7 presents a gallery of faith and compassion that reveals the identity of Jesus as the messianic Son of God. The chapter opens with the centurion of Capernaum — a Gentile soldier who demonstrates a quality of faith Jesus has not found even in Israel. His humble acknowledgment that a word from Jesus suffices reveals the unlimited authority of the Saviour over distance and disease. This Gentile''s faith stands as an implicit rebuke to the unbelief of those who have had every privilege of Torah and temple.' ||
  'The raising of the widow''s son at Nain (vv.11-17) is Luke''s only resurrection miracle unique to his Gospel, chosen to demonstrate that Jesus is the Lord of life as well as healer of disease. The compassion of Jesus is not merely emotional sympathy but divine action that overturns death itself. The crowd''s response — "God hath visited his people" — echoes Zechariah''s Benedictus and confirms the fulfilment of prophetic hope. Together the two miracles illustrate the twin categories of messianic work recited in verse 22: healing and resurrection.' ||
  'The embassy from John the Baptist (vv.18-35) forms the theological centre of the chapter. John, imprisoned and hearing of the works of Christ, sends to ask whether Jesus is truly "he that should come." Jesus''s answer is not a direct affirmation but a recital of messianic deeds drawn from Isaiah, each category corresponding to OT prophetic expectation. Blessed is the man who is not offended by the form in which the Messiah comes. Jesus then turns to the crowd and delivers the highest tribute ever paid to a human being: John is greater than any prophet, yet the least in the kingdom is greater still — not by personal merit but by participatory privilege.' ||
  'The chapter closes with the most intimate scene of the entire chapter: a sinful woman who washes Jesus''s feet with her tears, dries them with her hair, and anoints them with ointment. Simon the Pharisee''s silent contempt provides the foil for Jesus''s parable of two debtors. The key theological syllogism is powerful: she loved much because she was forgiven much. The forgiveness was not earned by the love — the love was the evidence that forgiveness had already occurred. The declaration "Thy faith hath saved thee; go in peace" closes the chapter with the same gospel offer that echoes through all of Luke.',
  'Compassion, Faith, and the Identity of the Son of God',
  'θεραπεύω (therapeuō)',
  'therapeuō means to heal, attend to, or cure. Luke, the physician, uses it more than any other Gospel writer, and in this chapter it introduces the full range of messianic healing — distance healing, resurrection, and spiritual restoration — that together answer John''s question about the identity of the Coming One.',
  '["The Great Faith of a Gentile: Centurion''s Servant Healed (vv.1-10)","The Lord of Life: Widow''s Son Raised at Nain (vv.11-17)","Are You the Coming One? John''s Question and Jesus''s Answer (vv.18-23)","Greater Than a Prophet: Jesus''s Testimony About John (vv.24-35)","Much Forgiven, Much Love: The Sinful Woman Anoints Jesus (vv.36-50)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now when he had ended all his sayings in the audience of the people, he entered into Capernaum.', 'Ἐπειδὴ ἐπλήρωσεν πάντα τὰ ῥήματα αὐτοῦ εἰς τὰς ἀκοὰς τοῦ λαοῦ, εἰσῆλθεν εἰς Καφαρναούμ.', 'Epeidē eplērōsen panta ta rhēmata autou eis tas akoas tou laou, eisēlthen eis Kapharnaum.', 'The transition from the Sermon on the Plain is smooth and immediate. "All his sayings" (panta ta rhēmata) signals that the discourse was complete, not interrupted. Capernaum was Jesus''s ministry base (4:31), the city of headquarters where he would encounter the next test of his authority.', NULL),
  (2, 'And a certain centurion''s servant, who was dear unto him, was sick, and ready to die.', 'Ἑκατοντάρχου δέ τινος δοῦλος κακῶς ἔχων ἤμελλεν τελευτᾶν, ὃς ἦν αὐτῷ ἔντιμος.', 'Hekatontarchou de tinos doulos kakōs echōn ēmellen teleutān, hos ēn autō entimos.', 'The centurion commanded 100 Roman soldiers. His servant (doulos, a slave) was "dear unto him" (entimos — highly valued, esteemed). The word is used elsewhere for precious stones, indicating genuine personal regard rather than mere economic loss. The illness is described as near-fatal, setting the stage for an urgent appeal.', NULL),
  (3, 'And when he heard of Jesus, he sent unto him the elders of the Jews, beseeching him that he would come and heal his servant.', 'ἀκούσας δὲ περὶ τοῦ Ἰησοῦ, ἀπέστειλεν πρὸς αὐτὸν πρεσβυτέρους τῶν Ἰουδαίων, ἐρωτῶν αὐτὸν ὅπως ἐλθὼν διασώσῃ τὸν δοῦλον αὐτοῦ.', 'akousas de peri tou Iēsou, apesteilen pros auton presbuterous tōn Ioudaiōn, erōtōn auton hopōs elthōn diasōsē ton doulon autou.', 'The centurion''s approach through Jewish elders shows cultural sensitivity and respect for Jewish customs. He does not presume to approach a Jewish rabbi directly. Faith here is not passive belief but active, resourceful pursuit of help. "Beseeching" (erōtōn) is the imperfect tense, suggesting persistent appeal.', NULL),
  (4, 'And when they came to Jesus, they besought him instantly, saying, That he was worthy for whom he should do this:', 'οἱ δὲ παραγενόμενοι πρὸς τὸν Ἰησοῦν παρεκάλουν αὐτὸν σπουδαίως, λέγοντες ὅτι Ἄξιός ἐστιν ᾧ παρέξῃ τοῦτο,', 'hoi de paragenomenoi pros ton Iēsoun parekaloun auton spoudaiōs, legontes hoti Axios estin hō parexē touto,', 'The elders'' intercession is earnest (spoudaiōs — urgently, diligently). They present the centurion''s worthiness (axios) based on his deeds, which is the human evaluation. Jesus''s response will reframe "worthiness" in terms of faith, not works. The elders argue from merit; the centurion will argue from unworthiness.', NULL),
  (5, 'For he loveth our nation, and he hath built us a synagogue.', 'ἀγαπᾷ γὰρ τὸ ἔθνος ἡμῶν, καὶ τὴν συναγωγὴν αὐτὸς ᾠκοδόμησεν ἡμῖν.', 'agapa gar to ethnos hēmōn, kai tēn sunagōgēn autos ōkodomēsen hēmin.', 'The centurion''s synagogue-building demonstrates concrete benevolence. Such patronage was unusual and evidenced genuine love for the Jewish people, perhaps reflecting a God-fearer''s attraction to Jewish monotheism. Luke, writing for Gentile readers, presents this Gentile as a model of generosity and faith.', NULL),
  (6, 'Then Jesus went with them. And when he was now not far from the house, the centurion sent friends to him, saying unto him, Lord, trouble not thyself: for I am not worthy that thou shouldest enter under my roof:', 'ὁ δὲ Ἰησοῦς ἐπορεύετο σὺν αὐτοῖς. ἤδη δὲ αὐτοῦ οὐ μακρὰν ἀπέχοντος ἀπὸ τῆς οἰκίας, ἔπεμψεν φίλους ὁ ἑκατοντάρχης λέγων αὐτῷ, Κύριε, μὴ σκύλλου· οὐ γὰρ ἱκανός εἰμι ἵνα ὑπὸ τὴν στέγην μου εἰσέλθῃς·', 'ho de Iēsous eporeueto sun autois. ēdē de autou ou makran apechontos apo tēs oikias, epempsen philous ho hekatontarchēs legōn autō, Kurie, mē skulou; ou gar hikanos eimi hina hupo tēn stegēn mou eiselthēs;', '"Lord" (Kurie) acknowledges Jesus''s authority. "I am not worthy" (hikanos — sufficient, fit) is the opposite of what the elders said. This humility is not false modesty but a profound recognition of the holiness of Jesus. The word hikanos is related to the Baptist''s "not worthy to unloose his sandals" (3:16), linking the centurion''s faith to John''s Christology.', NULL),
  (7, 'Wherefore neither thought I myself worthy to come unto thee: but say in a word, and my servant shall be healed.', 'διὸ οὐδὲ ἐμαυτὸν ἠξίωσα πρὸς σέ ἐλθεῖν· ἀλλὰ εἰπὲ λόγῳ, καὶ ἰαθήτω ὁ παῖς μου.', 'dio oude emauton ēxiōsa pros se elthein; alla eipe logō, kai iathētō ho pais mou.', '"Say in a word" (eipe logō — say with/by a word) is the heart of this remarkable faith. The centurion does not ask Jesus to touch, pray, or perform a ritual — just to speak. This is creation-faith: trust that the word of Jesus has power equivalent to the word of God in Genesis. "My servant" here uses paida, possibly indicating a higher-status household servant or even a young boy.', NULL),
  (8, 'For I also am a man set under authority, having under me soldiers, and I say unto one, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.', 'καὶ γὰρ ἐγὼ ἄνθρωπός εἰμι ὑπὸ ἐξουσίαν τασσόμενος, ἔχων ὑπ'' ἐμαυτὸν στρατιώτας, καὶ λέγω τούτῳ, Πορεύθητι, καὶ πορεύεται, καὶ ἄλλῳ, Ἔρχου, καὶ ἔρχεται, καὶ τῷ δούλῳ μου, Ποίησον τοῦτο, καὶ ποιεῖ.', 'kai gar egō anthrōpos eimi hupo exousian tassomenos, echōn hup'' emauton stratiōtas, kai legō toutō, Poreuthēti, kai poreuetai, kai allō, Erchou, kai erchetai, kai tō doulō mou, Poiēson touto, kai poiei.', 'The a fortiori argument is brilliant: if I — a mere man under authority — can command soldiers with a word and they obey, how much more can you — who possess supreme authority — command disease with a word? The centurion understands authority structures better than the religious leaders. Exousia (authority) is the key word; the same word was used of Jesus''s teaching in 4:32.', NULL),
  (9, 'When Jesus heard these things, he marvelled at him, and turned him about, and said unto the people that followed him, I say unto you, I have not found so great faith, no, not in Israel.', 'ἀκούσας δὲ ταῦτα ὁ Ἰησοῦς ἐθαύμασεν αὐτόν, καὶ στραφεὶς τῷ ἀκολουθοῦντι αὐτῷ ὄχλῳ εἶπεν, Λέγω ὑμῖν, οὐδὲ ἐν τῷ Ἰσραὴλ τοσαύτην πίστιν εὗρον.', 'akousas de tauta ho Iēsous ethaumasen auton, kai strapheis tō akolouthounti autō ochlō eipen, Legō humin, oude en tō Israēl tosautēn pistin heuron.', 'Jesus "marvelled" (ethaumasen) — one of only two instances in the Gospels where Jesus marvels (the other is Mark 6:6, at unbelief). Here he marvels at faith. The public declaration — "not in Israel" — is a stunning rebuke. A Gentile soldier surpasses the covenant people in faith. This anticipates the universal mission and the inclusion of Gentiles in Luke-Acts.', NULL),
  (10, 'And they that were sent, returning to the house, found the servant whole that had been sick.', 'καὶ ὑποστρέψαντες οἱ πεμφθέντες εἰς τὸν οἶκον εὗρον τὸν δοῦλον ὑγιαίνοντα.', 'kai hupostrepsantes hoi pemphthenetes eis ton oikon heuron ton doulon hugiainonta.', 'The healing is instantaneous and complete (hugiainonta — in a state of health, whole). Matthew''s parallel (8:13) notes it happened "in that selfsame hour." Luke does not specify the moment but focuses on the discovery of wholeness. The faith of the centurion, not the physical presence of Jesus, was the channel through which healing came — demonstrating that faith, not proximity, is the operative factor.', NULL),
  (11, 'And it came to pass the day after, that he went into a city called Nain; and many of his disciples went with him, and much people.', 'Καὶ ἐγένετο ἐν τῇ ἑξῆς ἐπορεύθη εἰς πόλιν καλουμένην Ναΐν· καὶ συνεπορεύοντο αὐτῷ οἱ μαθηταὶ αὐτοῦ ἱκανοὶ καὶ ὄχλος πολύς.', 'Kai egeneto en tē hexēs eporeuēthē eis polin kaloumenēn Nain; kai suneporeuonto autō hoi mathētai autou hikanoi kai ochlos polus.', 'Nain is about 25 miles south of Capernaum in Galilee, near Shunem where Elisha raised the Shunammite''s son (2 Kgs 4:8-37). The geographical echo is deliberate — Luke is about to present Jesus as greater than Elisha. The large company with Jesus creates a double procession at the city gate: the crowd of life meeting the procession of death.', NULL),
  (12, 'Now when he came nigh to the gate of the city, behold, there was a dead man carried out, the only son of his mother, and she was a widow: and much people of the city was with her.', 'ὡς δὲ ἤγγισεν τῇ πύλῃ τῆς πόλεως, καὶ ἰδοὺ ἐξεκομίζετο τεθνηκὼς υἱὸς μονογενὴς τῇ μητρὶ αὐτοῦ, καὶ αὐτὴ ἦν χήρα, καὶ ὄχλος τῆς πόλεως ἱκανὸς ἦν σὺν αὐτῇ.', 'hōs de ēngisen tē pulē tēs poleōs, kai idou exekomizeto tethnēkōs huios monogenēs tē mētri autou, kai autē ēn chēra, kai ochlos tēs poleōs hikanos ēn sun autē.', '"Only son" (monogenēs) is the same word used of Isaac and of Jesus himself in John 3:16. The woman is a widow — already bereft of her husband, now losing her only son, her sole support and protection in an ancient world with no social safety net. Luke''s repeated attention to widows (2:37, 4:25-26, 18:1-8, 21:2) reflects both his pastoral concern and Jesus''s.', NULL),
  (13, 'And when the Lord saw her, he had compassion on her, and said unto her, Weep not.', 'καὶ ἰδὼν αὐτὴν ὁ Κύριος ἐσπλαγχνίσθη ἐπ'' αὐτῇ, καὶ εἶπεν αὐτῇ, Μὴ κλαῖε.', 'kai idōn autēn ho Kurios esplanchnisthē ep'' autē, kai eipen autē, Mē klaie.', 'Luke uses "the Lord" (Kurios) as a narrative title for Jesus — a post-resurrection perspective written back into the ministry account, affirming his divine identity. "Had compassion" (esplanchnisthē) is from splanchnon (bowels, the seat of deep emotion in Jewish thought). This is not sentiment but the visceral mercy of God encountering human suffering. No request was made — the compassion of Jesus moved first.', NULL),
  (14, 'And he came and touched the bier: and they that bare him stood still. And he said, Young man, I say unto thee, Arise.', 'καὶ προσελθὼν ἥψατο τῆς σοροῦ, οἱ δὲ βαστάζοντες ἔστησαν, καὶ εἶπεν, Νεανίσκε, σοὶ λέγω, ἐγέρθητι.', 'kai proselthōn hēpsato tēs sorou, hoi de bastazontes estēsan, kai eipen, Neaniske, soi legō, egerthēti.', 'Touching the bier (soros — funeral stretcher/coffin) rendered a person ceremonially unclean under the Law (Num 19:11,16). Jesus deliberately touches the untouchable — as with the leper (5:13) — not to be defiled but to cleanse and restore. "Young man, I say unto thee" (Neaniske, soi legō) echoes Elisha''s "arise" to the Shunammite''s son. But Elisha prayed; Jesus commands. The authority is direct and personal.', NULL),
  (15, 'And he that was dead sat up, and began to speak. And he delivered him to his mother.', 'καὶ ἀνεκάθισεν ὁ νεκρὸς καὶ ἤρξατο λαλεῖν· καὶ ἔδωκεν αὐτὸν τῇ μητρὶ αὐτοῦ.', 'kai anekathisen ho nekros kai ērxato lalein; kai edōken auton tē mētri autou.', '"He that was dead sat up" (anekathisen ho nekros) — Luke the physician notes the physical action precisely. The use of nekros (dead one) while describing him sitting up creates a dramatic juxtaposition. "He delivered him to his mother" exactly echoes the LXX of 1 Kings 17:23, where Elijah restores the widow of Zarephath''s son — a deliberate literary echo confirming Jesus as the fulfilment of prophetic ministry.', NULL),
  (16, 'And there came a fear on all: and they glorified God, saying, That a great prophet is risen up among us; and, That God hath visited his people.', 'ἔλαβεν δὲ φόβος πάντας, καὶ ἐδόξαζον τὸν Θεόν, λέγοντες ὅτι Προφήτης μέγας ἠγέρθη ἐν ἡμῖν, καὶ ὅτι Ἐπεσκέψατο ὁ Θεὸς τὸν λαὸν αὐτοῦ.', 'elaben de phobos pantas, kai edoxazon ton Theon, legontes hoti Prophētēs megas ēgerthē en hēmin, kai hoti Epeskepsato ho Theos ton laon autou.', '"God hath visited his people" (epeskepsato ho Theos ton laon autou) is verbatim from the LXX of Ruth 1:6 and echoes Zechariah''s Benedictus (1:68: "he hath visited and redeemed his people"). The crowd identifies Jesus as a "great prophet," which is insufficient Christology but genuine recognition. Luke uses their response to confirm the theological meaning of the miracle: the eschatological visitation of God has begun.', NULL),
  (17, 'And this rumour of him went forth throughout all Judaea, and throughout all the region round about.', 'καὶ ἐξῆλθεν ὁ λόγος οὗτος ἐν ὅλῃ τῇ Ἰουδαίᾳ περὶ αὐτοῦ καὶ πάσῃ τῇ περιχώρῳ.', 'kai exēlthen ho logos houtos en holē tē Ioudaia peri autou kai pasē tē perichōrō.', '"Rumour" (logos — word, report) spread beyond Galilee into Judaea. Luke uses the geographic spread of the report to indicate the mounting of messianic expectation that sets the stage for John''s question. The word logos here is ironic — it is the logos (Word) himself who is the content of the report that goes forth.', NULL),
  (18, 'And the disciples of John shewed him of all these things.', 'Καὶ ἀπήγγειλαν Ἰωάννῃ οἱ μαθηταὶ αὐτοῦ περὶ πάντων τούτων.', 'Kai apēngeilan Iōannē hoi mathētai autou peri pantōn toutōn.', 'John the Baptist was imprisoned by Herod Antipas (3:19-20). His disciples maintained contact and reported the works of Jesus. The information "all these things" encompasses the two miracles just narrated plus the ministry of chapters 4-6. The report precipitates John''s crucial question — not doubt but a desire for confirmed identification.', NULL),
  (19, 'And John calling unto him two of his disciples sent them to Jesus, saying, Art thou he that should come? or look we for another?', 'καὶ προσκαλεσάμενος δύο τινὰς τῶν μαθητῶν αὐτοῦ ὁ Ἰωάννης ἔπεμψεν πρὸς τὸν Κύριον λέγων, Σὺ εἶ ὁ ἐρχόμενος ἢ ἄλλον προσδοκῶμεν;', 'kai proskalesamenos duo tinas tōn mathētōn autou ho Iōannēs epempsen pros ton Kurion legōn, Su ei ho erchomenos ē allon prosdokōmen?', '"He that should come" (ho erchomenos — the Coming One) was a recognized messianic title drawing on Psalm 118:26, Malachi 3:1, and Daniel 7. John had proclaimed such a figure in 3:16-17. The question may reflect John''s puzzlement that Jesus had not yet enacted the eschatological judgment (fire, winnowing) that John had predicted. It is a theological question about the timetable, not an expression of apostasy.', NULL),
  (20, 'When the men were come unto him, they said, John Baptist hath sent us unto thee, saying, Art thou he that should come? or look we for another?', 'παραγενόμενοι δὲ πρὸς αὐτὸν οἱ ἄνδρες εἶπον, Ἰωάννης ὁ Βαπτιστὴς ἀπέστειλεν ἡμᾶς πρὸς σέ, λέγων, Σὺ εἶ ὁ ἐρχόμενος ἢ ἄλλον προσδοκῶμεν;', 'paragenomenoi de pros auton hoi andres eipon, Iōannēs ho Baptistēs apesteilen hēmas pros se, legōn, Su ei ho erchomenos ē allon prosdokōmen?', 'The verbatim repetition of the question ensures that nothing is lost in transmission. The two-witness pattern (two disciples sent) may reflect the Jewish legal requirement of two witnesses for valid testimony (Deut 19:15). The question itself constitutes the most direct inquiry about Jesus''s messianic identity in Luke''s Gospel up to this point.', NULL),
  (21, 'And in that same hour he cured many of their infirmities and plagues, and of evil spirits; and unto many that were blind he gave sight.', 'ἐν ἐκείνῃ τῇ ὥρᾳ ἐθεράπευσεν πολλοὺς ἀπὸ νόσων καὶ μαστίγων καὶ πνευμάτων πονηρῶν, καὶ τυφλοῖς πολλοῖς ἐχαρίσατο βλέπειν.', 'en ekeinē tē hōra etherapeuse pollous apo nosōn kai mastigōn kai pneumatōn ponērōn, kai tuphlois pollois echarisato blepein.', 'Before answering verbally, Jesus performs the answer. "In that same hour" — his response is not a speech but a demonstration. The categories of healing (diseases, plagues, evil spirits, blindness) correspond exactly to Isaiah 35:5-6 and 61:1. Jesus is saying: look at what is happening and match it to your Scriptures. The messianic credentials are written in deeds, not declarations.', NULL),
  (22, 'Then Jesus answering said unto them, Go your way, and tell John what things ye have seen and heard; how that the blind see, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised, to the poor the gospel is preached.', 'καὶ ἀποκριθεὶς εἶπεν αὐτοῖς, Πορευθέντες ἀπαγγείλατε Ἰωάννῃ ἃ εἴδετε καὶ ἠκούσατε· τυφλοὶ ἀναβλέπουσιν, χωλοὶ περιπατοῦσιν, λεπροὶ καθαρίζονται, κωφοὶ ἀκούουσιν, νεκροὶ ἐγείρονται, πτωχοὶ εὐαγγελίζονται·', 'kai apokritheis eipen autois, Poreuthentes apangeillate Iōannē ha eidete kai ēkousate; tuphloi anablepousin, chōloi peripatousin, leproi katharizontai, kōphoi akouousin, nekroi egeirontai, ptōchoi euangelizontai;', 'Six categories of messianic works, all drawn from Isaiah (29:18-19; 35:5-6; 61:1; 26:19). Each is in the present tense (progressive: are seeing, are walking, etc.), indicating ongoing fulfilment. The climax is "to the poor the gospel is preached" — echoing the Nazareth manifesto (4:18). The order deliberately culminates in proclamation to the marginalized, Jesus''s distinctive messianic signature.', NULL),
  (23, 'And blessed is he, whosoever shall not be offended in me.', 'καὶ μακάριός ἐστιν ὃς ἐὰν μὴ σκανδαλισθῇ ἐν ἐμοί.', 'kai makarios estin hos ean mē skandalisthē en emoi.', '"Blessed" (makarios) — the beatitude form from the Sermon on the Plain (6:20-22). "Offended" (skandalisthē — caused to stumble, made to fall) refers to the stumbling block of a Messiah who heals and preaches rather than conquering and judging. The gentle, servant-form of messiahship was not what many expected. Blessed is the one who accepts the Messiah as he comes rather than as they imagined him.', NULL),
  (24, 'And when the messengers of John were departed, he began to speak unto the people concerning John, What went ye out into the wilderness for to see? A reed shaken with the wind?', 'Ἀπελθόντων δὲ τῶν ἀγγέλων Ἰωάννου ἤρξατο λέγειν πρὸς τοὺς ὄχλους περὶ Ἰωάννου, Τί ἐξήλθατε εἰς τὴν ἔρημον θεάσασθαι; κάλαμον ὑπὸ ἀνέμου σαλευόμενον;', 'Apelthontōn de tōn angelōn Iōannou ērxato legein pros tous ochlous peri Iōannou, Ti exēlthate eis tēn erēmon theasasthai; kalamon hupo anemou saleuomenon?', 'After the messengers leave, Jesus turns to publicly honour John. Three rhetorical questions are posed. "A reed shaken with the wind" — reeds grew abundantly in the Jordan region and bent easily in any breeze. The question implies: did you go to see a vacillating, weak-willed man? No — John was rock-solid in his testimony. The question demolishes any suspicion that John''s inquiry from prison indicated weakness.', NULL),
  (25, 'But what went ye out for to see? A man clothed in soft raiment? Behold, they which are gorgeously apparelled, and live delicately, are in kings'' courts.', 'ἀλλὰ τί ἐξήλθατε ἰδεῖν; ἄνθρωπον ἐν μαλακοῖς ἱματίοις ἠμφιεσμένον; ἰδοὺ οἱ ἐν ἱματισμῷ ἐνδόξῳ καὶ τρυφῇ ὑπάρχοντες ἐν τοῖς βασιλείοις εἰσίν.', 'alla ti exēlthate idein; anthrōpon en malakois himatiois ēmphiesmenon; idou hoi en himatismō endoxō kai truphē huparchontes en tois basileiois eisin.', '"Soft raiment" (malakois — soft, effeminate) contrasts with John''s rough camel-hair garment (cf. Matt 3:4). The courts of Herod Antipas — who imprisoned John — were full of men in gorgeous apparel. John was not an effete court preacher but a prophet of desert austerity. The irony is that John was held in Herod''s court precisely because he refused to be a court prophet.', NULL),
  (26, 'But what went ye out for to see? A prophet? Yea, I say unto you, and much more than a prophet.', 'ἀλλὰ τί ἐξήλθατε ἰδεῖν; προφήτην; ναί, λέγω ὑμῖν, καὶ περισσότερον προφήτου.', 'alla ti exēlthate idein; prophētēn; nai, legō humin, kai perissoteron prophētou.', '"Much more than a prophet" (perissoteron prophētou). The comparative form signals a qualitative advance. The OT prophets spoke of the Messiah from afar; John stood at the threshold and pointed to him face to face. His greatness lies not in his personal qualities but in his unique historical position as the immediate forerunner of the Lord.', NULL),
  (27, 'This is he, of whom it is written, Behold, I send my messenger before thy face, which shall prepare thy way before thee.', 'οὗτός ἐστιν περὶ οὗ γέγραπται, Ἰδοὺ ἀποστέλλω τὸν ἄγγελόν μου πρὸ προσώπου σου, ὃς κατασκευάσει τὴν ὁδόν σου ἔμπροσθέν σου.', 'houtos estin peri hou gegraptai, Idou apostellō ton angelon mou pro prosōpou sou, hos kataskeuasei tēn hodon sou emprosthen sou.', 'A composite citation of Malachi 3:1 and Exodus 23:20. Remarkably, the LXX of Malachi 3:1 reads "before my face" (referring to YHWH), but Jesus changes it to "before thy face" — applying to himself the role of YHWH being prepared for. This is an implicit but unmistakable divine self-identification. John is the messenger; Jesus is the Lord whom the messenger prepares.', NULL),
  (28, 'For I say unto you, Among those that are born of women there is not a greater prophet than John the Baptist: but he that is least in the kingdom of God is greater than he.', 'λέγω γὰρ ὑμῖν, μείζων ἐν γεννητοῖς γυναικῶν Ἰωάννου οὐδείς ἐστιν· ὁ δὲ μικρότερος ἐν τῇ βασιλείᾳ τοῦ Θεοῦ μείζων αὐτοῦ ἐστιν.', 'legō gar humin, meizōn en gennētois gunaikōn Iōannou oudeis estin; ho de mikroteros en tē basileia tou Theou meizōn autou estin.', 'The highest tribute ever paid to a human being — "no greater prophet." Yet the least kingdom participant surpasses him. The contrast is not personal merit but eschatological position. John stood at the border of the old age but did not enter the new. Those who receive the Spirit through Christ''s work participate in the inaugurated kingdom in a manner John could only announce. This verse defines greatness in terms of grace-position, not moral achievement.', NULL),
  (29, 'And all the people that heard him, and the publicans, justified God, being baptized with the baptism of John.', 'Καὶ πᾶς ὁ λαὸς ἀκούσας καὶ οἱ τελῶναι ἐδικαίωσαν τὸν Θεόν, βαπτισθέντες τὸ βάπτισμα Ἰωάννου·', 'Kai pas ho laos akousas kai hoi telōnai edikaiōsan ton Theon, baptisthenthes to baptisma Iōannou;', '"Justified God" (edikaiōsan ton Theon) means they declared God to be right — they acknowledged his righteousness in sending John and calling them to repentance. The publicans (tax collectors) — social and religious outcasts — responded in faith. Their response vindicates both John''s ministry and God''s wisdom in designing it. Baptism here is a past-tense action confirming their prior response to John''s preaching.', NULL),
  (30, 'But the Pharisees and lawyers rejected the counsel of God against themselves, being not baptized of him.', 'οἱ δὲ Φαρισαῖοι καὶ οἱ νομικοὶ τὴν βουλὴν τοῦ Θεοῦ ἠθέτησαν εἰς ἑαυτούς, μὴ βαπτισθέντες ὑπ'' αὐτοῦ.', 'hoi de Pharisaioi kai hoi nomikoi tēn boulēn tou Theou ēthētēsan eis heautous, mē baptisthenthes hup'' autou.', '"Rejected the counsel of God" (tēn boulēn tou Theou ēthētēsan) — a devastating indictment. The religious elite, who considered themselves arbiters of God''s will, actually set aside God''s redemptive plan. "Against themselves" (eis heautous) means the rejection operated to their own loss. Refusing John''s baptism was the first step in the tragic sequence culminating in the rejection of the Messiah.', NULL),
  (31, 'And the Lord said, Whereunto then shall I liken the men of this generation? and to what are they like?', 'Εἶπεν δὲ ὁ Κύριος, Τίνι οὖν ὁμοιώσω τοὺς ἀνθρώπους τῆς γενεᾶς ταύτης, καὶ τίνι εἰσὶν ὅμοιοι;', 'Eipen de ho Kurios, Tini oun homoiōsō tous anthrōpous tēs geneas tautēs, kai tini eisin homoioi?', '"This generation" (genea hautē) is a repeated phrase of judgment in the Synoptics (11:29,30,31,32,50,51; 17:25; 21:32). It refers to the generation standing before Jesus that was witnessing the messianic works and rejecting them. The rhetorical question "to what are they like?" introduces a parable of frustrated children — a deliberately mundane comparison for the dignified Pharisees.', NULL),
  (32, 'They are like unto children sitting in the marketplace, and calling one to another, and saying, We have piped unto you, and ye have not danced; we have mourned to you, and ye have not wept.', 'ὅμοιοί εἰσιν παιδίοις τοῖς ἐν ἀγορᾷ καθημένοις καὶ προσφωνοῦσιν ἀλλήλοις, λέγουσιν, Ηὐλήσαμεν ὑμῖν καὶ οὐκ ὠρχήσασθε· ἐθρηνήσαμεν καὶ οὐκ ἐκλαύσατε.', 'homoioi eisin paidiois tois en agorā kathēmenois kai prosphōnousin allēlois, legousin, Ēulēsamen humin kai ouk ōrchēsasthe; ethrēnēsamen kai ouk eklausate.', 'A vivid street-scene analogy: children playing games who cannot agree on which game to play. One group wants to play "wedding" (piped a merry tune — no one danced); the other wants to play "funeral" (mourned — no one wept). The generation was never going to be satisfied. The parable is a penetrating psychological portrait of willful, fickle unbelief.', NULL),
  (33, 'For John the Baptist came neither eating bread nor drinking wine; and ye say, He hath a devil.', 'ἐλήλυθεν γὰρ Ἰωάννης ὁ Βαπτιστὴς μήτε ἄρτον ἐσθίων μήτε οἶνον πίνων, καὶ λέγετε, Δαιμόνιον ἔχει.', 'elēluthen gar Iōannēs ho Baptistēs mēte arton esthiōn mēte oinon pinōn, kai legete, Daimonion echei.', 'The application of the parable: John came with ascetic austerity (no bread, no wine — Nazirite-like), playing the mourning pipe of judgment and repentance. They refused to mourn. They accused him of having a demon. The religious leaders found a reason to dismiss every messenger God sent, regardless of the messenger''s lifestyle.', NULL),
  (34, 'The Son of man is come eating and drinking; and ye say, Behold a gluttonous man, and a winebibber, a friend of publicans and sinners!', 'ἐλήλυθεν ὁ Υἱὸς τοῦ ἀνθρώπου ἐσθίων καὶ πίνων, καὶ λέγετε, Ἰδοὺ ἄνθρωπος φάγος καὶ οἰνοπότης, φίλος τελωνῶν καὶ ἁμαρτωλῶν.', 'elēluthen ho Huios tou anthrōpou esthiōn kai pinōn, kai legete, Idou anthrōpos phagos kai oinopotēs, philos telōnōn kai hamartolon.', 'Jesus came playing the wedding pipe of kingdom joy, eating and drinking at tables with sinners. They refused to dance. They accused him of gluttony and drunkenness. "Friend of publicans and sinners" was meant as an insult; Jesus turns it into a self-description of his mission (15:1-2; 19:10). No messenger of God — austere or joyful — would satisfy those determined not to respond.', NULL),
  (35, 'But wisdom is justified of all her children.', 'καὶ ἐδικαιώθη ἡ σοφία ἀπὸ πάντων τῶν τέκνων αὐτῆς.', 'kai edikaiōthē hē sophia apo pantōn tōn teknōn autēs.', '"Wisdom is justified of all her children" — a proverbial conclusion. Divine wisdom is vindicated by those who are her children (i.e., those who receive her). Both John''s asceticism and Jesus''s table fellowship are expressions of the same divine wisdom. The tax collectors and sinners (v.29) — wisdom''s true children — recognized and received both messengers. The Pharisees, who claimed wisdom, were strangers to it.', NULL),
  (36, 'And one of the Pharisees desired him that he would eat with him. And he went into the Pharisee''s house, and sat down to meat.', 'Ἠρώτα δέ τις αὐτὸν τῶν Φαρισαίων ἵνα φάγῃ μετ'' αὐτοῦ· καὶ εἰσελθὼν εἰς τὸν οἶκον τοῦ Φαρισαίου κατεκλίθη.', 'Ērōta de tis auton tōn Pharisaiōn hina phagē met'' autou; kai eiselthōn eis ton oikon tou Pharisaiou kateklithē.', 'The irony is immediate: Jesus was just accused of being a "friend of sinners." Now a Pharisee invites him to dinner. Jesus accepts — he is the friend of all people. The omission of the formal kiss, foot-washing, and anointing (noted in v.45) in Simon''s reception was a deliberate slight, placing Jesus in the category of an unwelcome or unimportant guest.', NULL),
  (37, 'And, behold, a woman in the city, which was a sinner, when she knew that Jesus sat at meat in the Pharisee''s house, brought an alabaster box of ointment,', 'καὶ ἰδοὺ γυνὴ ἥτις ἦν ἐν τῇ πόλει ἁμαρτωλός, καὶ ἐπιγνοῦσα ὅτι κατάκειται ἐν τῇ οἰκίᾳ τοῦ Φαρισαίου, κομίσασα ἀλάβαστρον μύρου,', 'kai idou gunē hētis ēn en tē polei hamartōlos, kai epignousa hoti katakeitai en tē oikia tou Pharisaiou, komisasa alabastron murou,', '"A woman in the city, which was a sinner" — a known public sinner, likely a prostitute. She came uninvited to a Pharisee''s dinner party, which required courage bordering on recklessness. In Hellenistic dining customs, uninvited guests could enter while men reclined; she exploited this. The alabaster flask (alabastron) of ointment (muron — aromatic oil/perfume) was a precious and costly possession.', NULL),
  (38, 'And stood at his feet behind him weeping, and began to wash his feet with tears, and did wipe them with the hairs of her head, and kissed his feet, and anointed them with the ointment.', 'καὶ στᾶσα ὀπίσω παρὰ τοὺς πόδας αὐτοῦ κλαίουσα, ἤρξατο βρέχειν τοὺς πόδας αὐτοῦ τοῖς δάκρυσιν, καὶ ταῖς θριξὶν τῆς κεφαλῆς αὐτῆς ἐξέμασσεν, καὶ κατεφίλει τοὺς πόδας αὐτοῦ καὶ ἤλειφεν τῷ μύρῳ.', 'kai stasa opisō para tous podas autou klaiōusa, ērxato brechein tous podas autou tois dakrusin, kai tais thrixin tēs kephalēs autēs exemassen, kai katefilei tous podas autou kai ēleiPhen tō murō.', 'A stunning display of extravagant love and profound humility. In Jewish culture, a woman''s unbound hair was a matter of modesty — yet she lets her hair down in public to dry Jesus''s feet. She weeps (present/continuous) — the tears are not merely a brief outburst but sustained. She kisses (katephilei — the intensive form, kissing repeatedly) his feet. The feet were the most humble place to give honour, and anointing them with precious ointment was an act of costly devotion.', NULL),
  (39, 'Now when the Pharisee which had bidden him saw it, he spake within himself, saying, This man, if he were a prophet, would have known who and what manner of woman this is that toucheth him: for she is a sinner.', 'ἰδὼν δὲ ὁ Φαρισαῖος ὁ καλέσας αὐτὸν εἶπεν ἐν ἑαυτῷ λέγων, Οὗτος εἰ ἦν προφήτης, ἐγίνωσκεν ἂν τίς καὶ ποταπὴ ἡ γυνὴ ἥτις ἅπτεται αὐτοῦ, ὅτι ἁμαρτωλός ἐστιν.', 'idōn de ho Pharisaios ho kalesas auton eipen en heautō legōn, Houtos ei ēn prophētēs, eginōsken an tis kai potapē hē gunē hētis haptetai autou, hoti hamartōlos estin.', 'Simon thinks to himself — but Jesus knows his thoughts (cf. 5:22; 6:8), which is itself the proof of the prophetic knowledge Simon doubted Jesus possessed. Simon''s syllogism: a real prophet would know she is a sinner and would therefore reject her touch. Jesus''s counter-syllogism will be: I know exactly who she is and I also know she has been forgiven. Knowledge and mercy go together in the Son of God.', NULL),
  (40, 'And Jesus answering said unto him, Simon, I have somewhat to say unto thee. And he saith, Master, say on.', 'καὶ ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν πρὸς αὐτόν, Σίμων, ἔχω σοί τι εἰπεῖν. ὁ δέ, Διδάσκαλε, εἰπέ, φησίν.', 'kai apokritheis ho Iēsous eipen pros auton, Simōn, echō soi ti eipein. ho de, Didaskale, eipe, phēsin.', '"Answering" (apokritheis) — Jesus answers the unspoken thought. This would have been startling to Simon. Jesus addresses him by name — "Simon" — personalizing the rebuke. Simon addresses Jesus as "Master" (Didaskale — Teacher), a respectful but non-messianic title. The contrast between the woman''s extravagant reverence and Simon''s cool respect frames the entire scene.', NULL),
  (41, 'There was a certain creditor which had two debtors: the one owed five hundred pence, and the other fifty.', 'Δύο χρεοφειλέται ἦσαν δανιστῇ τινι· ὁ εἷς ὤφειλεν δηνάρια πεντακόσια, ὁ δὲ ἕτερος πεντήκοντα.', 'Duo chreopheiletai ēsan danistē tini; ho heis ōpheilen dēnaria pentakosia, ho de heteros pentēkonta.', 'The parable of two debtors. A denarius was a day''s wage; 500 denarii represented nearly two years'' wages; 50 represented about seven weeks'' wages. Both debts are real, both are unpayable by the debtors on their own (otherwise they would have paid), and both are freely cancelled. The parable is not about the relative size of sins but about the relative experience of forgiveness.', NULL),
  (42, 'And when they had nothing to pay, he frankly forgave them both. Tell me therefore, which of them will love him most?', 'μὴ ἐχόντων δὲ αὐτῶν ἀποδοῦναι, ἀμφοτέροις ἐχαρίσατο. τίς οὖν αὐτῶν πλεῖον ἀγαπήσει αὐτόν;', 'mē echontōn de autōn apodounai, amphoterois echarisato. tis oun autōn pleion agapēsei auton?', '"Frankly forgave" (echarisato — freely gave, graced them with forgiveness). The verb is from charis (grace), highlighting that forgiveness is a gift. "When they had nothing to pay" — both were utterly insolvent. The question "which will love more?" is designed so that Simon must condemn himself by answering. His answer will reveal his own spiritual poverty.', NULL),
  (43, 'Simon answered and said, I suppose that he, to whom he forgave most. And he said unto him, Thou hast rightly judged.', 'ἀποκριθεὶς δὲ Σίμων εἶπεν, Ὑπολαμβάνω ὅτι ᾧ τὸ πλεῖον ἐχαρίσατο. ὁ δὲ εἶπεν αὐτῷ, Ὀρθῶς ἔκρινας.', 'apokritheis de Simōn eipen, Hupolambanō hoti hō to pleion echarisato. ho de eipen autō, Orthōs ekrinas.', '"I suppose" (hupolambanō — I assume, take it for granted) — Simon answers with slight reluctance, sensing the trap. "Thou hast rightly judged" (orthōs ekrinas) — Jesus affirms the answer before applying it. The trap closes: Simon has just confessed the principle by which he himself will be evaluated. The one who loves little demonstrates little awareness of forgiveness received.', NULL),
  (44, 'And he turned to the woman, and said unto Simon, Seest thou this woman? I entered into thine house, thou gavest me no water for my feet: but she hath washed my feet with tears, and wiped them with the hairs of her head.', 'καὶ στραφεὶς πρὸς τὴν γυναῖκα τῷ Σίμωνι ἔφη, Βλέπεις ταύτην τὴν γυναῖκα; εἰσῆλθόν σου εἰς τὴν οἰκίαν, ὕδωρ μοι ἐπὶ πόδας οὐκ ἔδωκας· αὕτη δὲ τοῖς δάκρυσιν ἔβρεξέν μου τοὺς πόδας καὶ ταῖς θριξὶν αὐτῆς ἐξέμαξεν.', 'kai strapheis pros tēn gunaika tō Simōni ephē, Blepeis tautēn tēn gunaika; eisēlthon sou eis tēn oikian, hudōr moi epi podas ouk edōkas; hautē de tois dakrusin ebrexen mou tous podas kai tais thrixin autēs exemaxen.', '"Seest thou this woman?" (Blepeis tautēn tēn gunaika?) — the dramatic turn. Jesus has been facing Simon; now he turns to the woman and speaks to Simon. He forces Simon to truly see her — not as a category ("sinner") but as a person. Three contrasts follow: no water/tears; no kiss/continual kissing; no anointing/precious ointment. Each absence in Simon''s hospitality is more than a social failure — it reveals the poverty of a heart that does not know it is a debtor.', NULL),
  (45, 'Thou gavest me no kiss: but this woman since the time I came in hath not ceased to kiss my feet.', 'φίλημά μοι οὐκ ἔδωκας· αὕτη δὲ ἀφ'' ἧς εἰσῆλθον οὐ διέλιπεν καταφιλοῦσά μου τοὺς πόδας.', 'philēma moi ouk edōkas; hautē de aph'' hēs eisēlthen ou dielipen kataphilousa mou tous podas.', '"No kiss" — the greeting kiss (philēma) was a standard mark of welcome. Its absence was a calculated social slight. The woman, by contrast, had not ceased (ou dielipen — uninterrupted, continuous action) kissing his feet from the moment he arrived. The intensity and persistence of her devotion contrasts absolutely with Simon''s cold indifference. She honored the feet Simon would not even greet.', NULL),
  (46, 'My head with oil thou didst not anoint: but this woman hath anointed my feet with ointment.', 'ἐλαίῳ τὴν κεφαλήν μου οὐκ ἤλειψας· αὕτη δὲ μύρῳ ἤλειψεν τοὺς πόδας μου.', 'elaiō tēn kephalēn mou ouk ēleipsas; hautē de murō ēlEipsen tous podas mou.', 'Common olive oil on the head was a courteous gesture for a guest; Simon provided none. The woman used costly myron (perfume/ointment) — far more valuable — and applied it not to the head (the place of honor) but to the feet (the place of humility). The quality of her gift was inversely proportional to the place she applied it. Her extravagance in the lowest place exceeded Simon''s parsimony at every point.', NULL),
  (47, 'Wherefore I say unto thee, Her sins, which are many, are forgiven; for she loved much: but to whom little is forgiven, the same loveth little.', 'οὗ χάριν λέγω σοι, ἀφέωνταί αἱ ἁμαρτίαι αὐτῆς αἱ πολλαί, ὅτι ἠγάπησεν πολύ· ᾧ δὲ ὀλίγον ἀφίεται, ὀλίγον ἀγαπᾷ.', 'hou charin legō soi, aphiōntai hai hamartiai autēs hai pollai, hoti ēgapēsen polu; hō de oligon aphietai, oligon agapa.', 'The theological climax of the chapter. The grammar is crucial: "her sins are forgiven" (perfect passive — a past completed action with present results) "because she loved much." This does not mean love earns forgiveness; the parable (vv.41-42) has already established that forgiveness precedes and produces love. The "because" (hoti) indicates evidence, not cause. Her love was the fruit and proof of forgiveness already received, not the price that purchased it.', NULL),
  (48, 'And he said unto her, Thy sins are forgiven.', 'εἶπεν δὲ αὐτῇ, Ἀφέωνταί σου αἱ ἁμαρτίαι.', 'eipen de autē, Aphiōntai sou hai hamartiai.', 'A direct, personal, present-tense declaration to the woman herself. Not "thy sins were forgiven" at some past moment, but "are forgiven" — confirming to her what had already occurred and assuring her of its reality. This declaration publicly validates what the Spirit had already worked in her heart. The same form of direct divine absolution appears in 5:20 (the paralytic).', NULL),
  (49, 'And they that sat at meat with him began to say within themselves, Who is this that forgiveth sins also?', 'καὶ ἤρξαντο οἱ συνανακείμενοι λέγειν ἐν ἑαυτοῖς, Τίς οὗτός ἐστιν ὃς καὶ ἁμαρτίας ἀφίησιν;', 'kai ērxanto hoi sunanakreimenoi legein en heautois, Tis houtos estin hos kai hamartias aphiēsin?', '"Who is this that forgiveth sins also?" (kai hamartias aphiēsin) — the same question raised in 5:21 at the healing of the paralytic. "Also" (kai) may indicate: as well as performing miracles. The dinner guests perceive the implicit claim to divine prerogative. They are not yet ready to arrive at the conclusion that would explain it. The question hangs unanswered — Luke''s device for leading the reader to supply the answer: He is the Son of God.', NULL),
  (50, 'And he said to the woman, Thy faith hath saved thee; go in peace.', 'εἶπεν δὲ πρὸς τὴν γυναῖκα, Ἡ πίστις σου σέσωκέν σε· πορεύου εἰς εἰρήνην.', 'eipen de pros tēn gunaika, Hē pistis sou sesōken se; poreuou eis eirēnēn.', '"Thy faith hath saved thee" (sesōken — perfect tense: has saved and the salvation stands). The final word is to the woman, not to the critics. Faith (pistis) — not the tears, not the ointment, not the love per se — is identified as the saving instrument. "Go in peace" (poreuou eis eirēnēn) echoes the OT shalom-dismissal (1 Sam 1:17; 20:42) and anticipates the leper''s healing formula (17:19). Peace here is not mere emotional calm but wholeness, reconciliation with God, and the fullness of covenant blessing. This is the gospel in miniature.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 7;
